-- Migración 015: Tabla plana para la página Rates (pageId=rates).
-- 2 filas: locale 'en' y 'es'. API content.php GET/PUT pageId=rates.
--
-- El front (RatesContentFromApi) espera content.hero, content.pricing (title, sessions),
-- content.insurance (title, description, providers, providerList, modal),
-- content.paymentOptions (title, description, options), content.faq (title, questions),
-- content.ctaSection (title, subtitle, primaryCTA, secondaryCTA).
-- Los JSON por idioma se combinan en la API para devolver { en, es }.
--
-- meta.lastUpdated: rellenar en ISO 8601 para evitar ZodError (ver PATRON-CONTENIDO-DESDE-BD).
--
-- Ejecutar en la misma BD que public/api/content.php (phpMyAdmin o CLI).

CREATE TABLE IF NOT EXISTS page_rates (
  id INT AUTO_INCREMENT PRIMARY KEY,
  locale VARCHAR(5) NOT NULL UNIQUE COMMENT 'en or es',
  meta_last_updated VARCHAR(32),
  meta_version INT DEFAULT 1,
  seo_title VARCHAR(255) DEFAULT '',
  seo_description TEXT,
  hero_title VARCHAR(255) NOT NULL DEFAULT 'Rates',
  hero_subtitle VARCHAR(500) DEFAULT '',
  hero_background_image VARCHAR(500) DEFAULT '',
  hero_background_image_alt VARCHAR(255) DEFAULT '',
  pricing_json LONGTEXT NOT NULL COMMENT 'JSON: { title, sessions: [{ type, rate, duration }] } for this locale',
  insurance_json LONGTEXT NOT NULL COMMENT 'JSON: insurance block for this locale (title, description, providerList, providers, modal)',
  payment_options_json LONGTEXT NOT NULL COMMENT 'JSON: { title, description, options: [{ label, text }] }',
  faq_json LONGTEXT NOT NULL COMMENT 'JSON: { title, questions: [{ question, answer }] }',
  cta_section_json LONGTEXT NOT NULL COMMENT 'JSON: { title, subtitle, primaryCTA, secondaryCTA }',
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- INSERT con datos reales desde export page_content. Generado con extract-rates-json.js
INSERT INTO page_rates (locale, meta_last_updated, meta_version, seo_title, seo_description, hero_title, hero_subtitle, hero_background_image, hero_background_image_alt, pricing_json, insurance_json, payment_options_json, faq_json, cta_section_json) VALUES
('en', '2024-01-15T10:00:00Z', 1, 'Rates - WholeSelf Counseling', 'Pricing, insurance, and payment options', 'Your well-being is worth investing in—we make our pricing clear, accessible, and honest.', 'We believe financial clarity is part of emotional safety. Our goal is to make therapy as accessible and transparent as possible by clearly outlining costs, accepted insurance plans, and payment options.', '/banner-rates.webp', 'Rates - WholeSelf Counseling', '{"title":"Fees for Therapy","sessions":[{"type":"Intake Appointment","rate":"$150","duration":"Initial consultation"},{"type":"Therapy Session","rate":"$125","duration":"Standard session"},{"type":"Couples Therapy Session","rate":"$150","duration":"Couples session"}]}', '{"title":"Insurance","description":"Therapy can be covered by your insurance. We believe that therapy should be accessible. Insurances that we are in network with and can accept:","providerList":["Aetna","Ambetter","Blue Cross Blue Shield","Cigna and Evernorth","Magellan","Medicare","Mines and Associates","New Mexico Medicaid","New Mexico Medical Insurance Pool","Optum","Presbyterian","Tricare","United Healthcare"],"providers":[{"label":"In-Network Insurance Providers","text":"We accept many insurance providers. Click below to see the complete list."},{"label":"Out-of-Network Options","text":"If you would like to use an insurance plan that we are not paneled with, we can provide you with a Superbill, a document that you can submit to your insurance provider for possible reimbursement for your appointment."},{"label":"Note","text":"We are always getting in network with more insurance providers. This list will update as more plans are accepted."}],"modal":{"title":"Accepted Insurance Providers","description":"We are in-network with the following insurance providers:","outOfNetworkInfo":"If you would like to use an insurance plan that we are not paneled with, we can provide you with a Superbill, a document that you can submit to your insurance provider for possible reimbursement for your appointment.","note":"We are always getting in network with more insurance providers. This list will update as more plans are accepted.","cta":{"text":"","href":""}}}', '{"title":"Payment Options","description":"We accept multiple payment methods to make therapy accessible.","options":[{"label":"Accepted Payment Methods","text":"We accept cash, credit card, PayPal, Health Savings Account (HSA), Venmo, and Flexible Savings Account (FSA)."},{"label":"Payment Timing","text":"Payment is due at the time of your appointment."},{"label":"Sliding Scale","text":"A sliding scale fee is available as needed."}]}', '{"title":"Frequently Asked Questions","questions":[{"question":"Do you accept insurance?","answer":"Yes, we are in-network with many insurance providers including Aetna, Blue Cross Blue Shield, Cigna, United Healthcare, Medicare, Medicaid, and others. We are always adding more insurance providers to our network. If your insurance is not in our network, we can provide a Superbill for possible reimbursement."},{"question":"What are my out-of-pocket costs?","answer":"If using insurance, your out-of-pocket costs depend on your insurance plan. You may have a copay or need to meet your deductible first. For self-pay clients, our fees are: Intake appointment $150, Therapy session $125, Couples therapy session $150. We recommend contacting your insurance provider to understand your specific benefits."},{"question":"Do you offer sliding scale or payment plans?","answer":"Yes, a sliding scale fee is available as needed. Please contact us to discuss your options and eligibility."},{"question":"What payment methods do you accept?","answer":"We accept cash, credit card, PayPal, Health Savings Account (HSA), Venmo, and Flexible Savings Account (FSA). Payment is due at the time of your appointment."},{"question":"What is a Superbill?","answer":"A Superbill is a detailed invoice that you can submit to your insurance provider for possible reimbursement if we are not in-network with your insurance plan. It contains all the necessary information your insurance company needs to process your claim."}]}', '{"title":"Ready to Get Started?","subtitle":"Have questions about pricing or insurance? We''re here to help.","primaryCTA":{"text":"Contact Us","href":"/contact"},"secondaryCTA":{"text":"Verify Insurance Coverage","href":"/contact"}}'),
('es', '2024-01-15T10:00:00Z', 1, 'Tarifas - WholeSelf Counseling', 'Precios, seguros y opciones de pago', 'Vale la pena invertir en tu bienestar —hacemos que nuestros precios sean claros, accesibles y honestos', 'Creemos que la claridad financiera es parte de la seguridad emocional. Nuestro objetivo es hacer que la terapia sea lo mas accesible y transparente posible, describiendo claramente los costos, los planes de seguro aceptados y las opciones de pago.', '/banner-rates.webp', 'Tarifas - WholeSelf Counseling', '{"title":"Tarifas de Terapia","sessions":[{"type":"Cita de Evaluacion Inicial","rate":"$150","duration":"Consulta inicial"},{"type":"Sesion de Terapia","rate":"$125","duration":"Sesion estandar"},{"type":"Sesion de Terapia de Pareja","rate":"$150","duration":"Sesion de pareja"}]}', '{"title":"Seguro","description":"La terapia puede estar cubierta por tu seguro. Creemos que la terapia debe ser accesible. Seguros con los que estamos en red y podemos aceptar:","providerList":["Aetna","Ambetter","Blue Cross Blue Shield","Cigna and Evernorth","Magellan","Medicare","Mines and Associates","New Mexico Medicaid","New Mexico Medical Insurance Pool","Optum","Presbyterian","Tricare","United Healthcare"],"providers":[{"label":"Proveedores de Seguro en Red","text":"Aceptamos muchos proveedores de seguro. Haz clic abajo para ver la lista completa."},{"label":"Opciones Fuera de Red","text":"Si deseas usar un plan de seguro con el que no estamos en red, podemos proporcionarte un Superbill, un documento que puedes enviar a tu proveedor de seguro para posible reembolso de tu cita."},{"label":"Nota","text":"Siempre estamos agregando mas proveedores de seguro a nuestra red. Esta lista se actualizara a medida que se acepten mas planes."}],"modal":{"title":"Proveedores de Seguro Aceptados","description":"Estamos en red con los siguientes proveedores de seguro:","outOfNetworkInfo":"Si deseas usar un plan de seguro con el que no estamos en red, podemos proporcionarte un Superbill, un documento que puedes enviar a tu proveedor de seguro para posible reembolso de tu cita.","note":"Siempre estamos agregando mas proveedores de seguro a nuestra red. Esta lista se actualizara a medida que se acepten mas planes.","cta":{"text":"","href":""}}}', '{"title":"Opciones de Pago","description":"Aceptamos multiples metodos de pago para hacer la terapia accesible.","options":[{"label":"Metodos de Pago Aceptados","text":"Aceptamos efectivo, tarjeta de credito, PayPal, Cuenta de Ahorros de Salud (HSA), Venmo y Cuenta de Ahorros Flexible (FSA)."},{"label":"Momento del Pago","text":"El pago se debe al momento de tu cita."},{"label":"Escala Deslizante","text":"Una tarifa de escala deslizante esta disponible segun sea necesario."}]}', '{"title":"Preguntas Frecuentes","questions":[{"question":"¿Aceptan seguro?","answer":"Si, estamos en red con muchos proveedores de seguro incluyendo Aetna, Blue Cross Blue Shield, Cigna, United Healthcare, Medicare, Medicaid y otros. Siempre estamos agregando mas proveedores de seguro a nuestra red. Si tu seguro no esta en nuestra red, podemos proporcionar un Superbill para posible reembolso."},{"question":"¿Cuales son mis costos de bolsillo?","answer":"Si usas seguro, tus costos de bolsillo dependen de tu plan de seguro. Puedes tener un copago o necesitar cumplir primero con tu deducible. Para clientes de pago directo, nuestras tarifas son: Cita de evaluacion inicial $150, Sesion de terapia $125, Sesion de terapia de pareja $150. Recomendamos contactar a tu proveedor de seguro para entender tus beneficios especificos."},{"question":"¿Ofrecen escala deslizante o planes de pago?","answer":"Si, una tarifa de escala deslizante esta disponible segun sea necesario. Por favor contactanos para discutir tus opciones y elegibilidad."},{"question":"¿Que metodos de pago aceptan?","answer":"Aceptamos efectivo, tarjeta de credito, PayPal, Cuenta de Ahorros de Salud (HSA), Venmo y Cuenta de Ahorros Flexible (FSA). El pago se debe al momento de tu cita."},{"question":"¿Que es un Superbill?","answer":"Un Superbill es una factura detallada que puedes enviar a tu proveedor de seguro para posible reembolso si no estamos en red con tu plan de seguro. Contiene toda la informacion necesaria que tu compania de seguros necesita para procesar tu reclamo."}]}', '{"title":"¿Listo para Comenzar?","subtitle":"¿Tienes preguntas sobre precios o seguro? Estamos aqui para ayudar.","primaryCTA":{"text":"Contactanos","href":"/contact"},"secondaryCTA":{"text":"Verificar Cobertura de Seguro","href":"/contact"}}')
ON DUPLICATE KEY UPDATE meta_last_updated=VALUES(meta_last_updated), meta_version=VALUES(meta_version), seo_title=VALUES(seo_title), seo_description=VALUES(seo_description), hero_title=VALUES(hero_title), hero_subtitle=VALUES(hero_subtitle), hero_background_image=VALUES(hero_background_image), hero_background_image_alt=VALUES(hero_background_image_alt), pricing_json=VALUES(pricing_json), insurance_json=VALUES(insurance_json), payment_options_json=VALUES(payment_options_json), faq_json=VALUES(faq_json), cta_section_json=VALUES(cta_section_json), updated_at=NOW();
